-- 1. Crear la Base de Datos
CREATE DATABASE IF NOT EXISTS incidenciasMolvizar;
USE incidenciasMolvizar;

-- 2. Tabla de Lugares (Para la lista de la P1 y el script de comentarios)
CREATE TABLE lugares (
    id INT AUTO_INCREMENT PRIMARY KEY,
    nombre_lugar VARCHAR(100) NOT NULL
);

-- 3. Tabla de Noticias
CREATE TABLE noticias (
    id INT AUTO_INCREMENT PRIMARY KEY,
    titulo VARCHAR(255) NOT NULL,
    fecha DATE NOT NULL,
    tipo VARCHAR(50),
    concejalia VARCHAR(100),
    personas TEXT,
    descripcion TEXT,
    id_lugar INT,
    FOREIGN KEY (id_lugar) REFERENCES lugares(id) ON DELETE SET NULL
);

-- 4. Tabla de Imágenes (Relación 1 a N)
CREATE TABLE imagenes (
    id INT AUTO_INCREMENT PRIMARY KEY,
    id_noticia INT NOT NULL,
    ruta_archivo VARCHAR(255) NOT NULL,
    descripcion_alt VARCHAR(255),
    es_portada BOOLEAN NOT NULL,
    FOREIGN KEY (id_noticia) REFERENCES noticias(id) ON DELETE CASCADE
);

-- 5. Tabla de Comentarios
CREATE TABLE comentarios (
    id INT AUTO_INCREMENT PRIMARY KEY,
    id_noticia INT NOT NULL,
    nombre VARCHAR(100) NOT NULL,
    email VARCHAR(100) NOT NULL,
    texto TEXT NOT NULL,
    fecha DATETIME DEFAULT CURRENT_TIMESTAMP,
    FOREIGN KEY (id_noticia) REFERENCES noticias(id) ON DELETE CASCADE
);

